import { UserAccess as UserAccessType } from "~/types/userAccess";
import InlineStack from "~/components/molecules/InlineStack";
import MainLayout from "~/components/templates/MainLayout";
import IconButton from "~/components/molecules/IconButton";
import AccessTopbar from "./components/AccessTopbar";
import Topbar from "~/components/molecules/Topbar";
import AccessList from "./components/AccessList";
import Button from "~/components/atoms/Button";
import { useState } from "@wordpress/element";
import Text from "~/components/atoms/Text";
import { __ } from "@wordpress/i18n";
/* <fs_premium_only> */
import { useGetUserAccessListQuery } from "~/store/api/userAccessApi__premium_only";
import { useAppDispatch, useAppSelector } from "~/store/hooks";
import { PAGE_OPTIONS } from "../ModuleDashboard/Dashboard";
import BlockStack from "~/components/molecules/BlockStack";
import SelectBox from "~/components/molecules/SelectBox";
import { useNotExist } from "./components/NotExist";
import SettingsRoute from "~/Routes/SettingsRoute";
import Pagination from "./components/Pagination";
import { useNavigate } from "react-router-dom";
import {
    selectUserAccess,
    setQueryArgs,
} from "~/store/features/userAccessSlice";
/* </fs_premium_only> */

const UserAccess = () => {
    const title = (
        <InlineStack gap={10}>
            <IconButton
                variant="white"
                rounded="md"
                name="passkey"
                color="primary"
                border
                borderColor="gray-200"
                fontSize="2xl"
                style={{
                    backgroundColor: "var(--pnpnd-gray-50)",
                }}
            />

            <Text color="gray-700" weight="semibold">
                {__("User Access", "ninja-drive")}
            </Text>
        </InlineStack>
    );

    const [selectedAccesses, setSelectedAccesses] = useState<UserAccessType[]>(
        [],
    );

    /* <fs_premium_only> */
    const { queryArgs } = useAppSelector(selectUserAccess);

    const { data, isLoading } = useGetUserAccessListQuery({
        base: queryArgs?.base,
        search: queryArgs?.search,
        order_by: queryArgs?.order_by,
        status: queryArgs?.status,
        order: queryArgs?.order,
        page: queryArgs?.page,
        per_page: queryArgs?.per_page,
    });

    const accessList = data?.data?.user_access?.list || [];

    const total_pages = data?.data?.user_access?.total_pages || 1;

    const current_page = data?.data?.user_access?.page || 1;

    const addDisabled =
        !data?.data?.remaining || data?.data?.remaining === null;

    const navigate = useNavigate();

    const dispatch = useAppDispatch();

    const { openNotExist } = useNotExist();

    const handleAddAccess = () => {
        if (addDisabled) {
            openNotExist();
            return;
        }
        navigate("/user-access/new/source/my-drive");
    };

    const add = (
        <Button variant="primary" startIcon="add" onClick={handleAddAccess}>
            {__("Add New Access", "ninja-drive")}
        </Button>
    );

    return (
        <SettingsRoute>
            <MainLayout>
                <MainLayout.ContentWrapper>
                    <Topbar leftContents={[title]} rightContents={[add]} />

                    <MainLayout.Content>
                        <InlineStack gap={10} align="between">
                            <InlineStack gap={5}>
                                <Text color="gray-700" weight="semibold">
                                    {__("All User Access", "ninja-drive")}
                                </Text>

                                <Text color="gray-600" size="sm">
                                    ({accessList.length}{" "}
                                    {__("items", "ninja-drive")})
                                </Text>
                            </InlineStack>

                            <Button
                                variant="outlined"
                                size="small"
                                startIcon="info"
                                href=""
                                target="_blank"
                            >
                                {__("Documentation", "ninja-drive")}
                            </Button>
                        </InlineStack>

                        <AccessTopbar
                            data={accessList}
                            selectedAccesses={selectedAccesses}
                            setSelectedAccesses={setSelectedAccesses}
                            onAdd={handleAddAccess}
                        />

                        <AccessList
                            data={accessList}
                            selectedAccesses={selectedAccesses}
                            setSelectedAccesses={setSelectedAccesses}
                            onAdd={handleAddAccess}
                            loading={isLoading}
                        />

                        {!isLoading && accessList && accessList.length > 0 && (
                            <BlockStack margin={15}>
                                <InlineStack gap={5} align="center">
                                    <Pagination
                                        currentPage={current_page}
                                        totalPages={total_pages || 1}
                                        onPageChange={(p) =>
                                            dispatch(setQueryArgs({ page: p }))
                                        }
                                    />

                                    <SelectBox
                                        placement="top"
                                        options={PAGE_OPTIONS}
                                        value={[String(queryArgs.per_page)]}
                                        onChange={(value) =>
                                            dispatch(
                                                setQueryArgs({
                                                    per_page: Number(value[0]),
                                                    page: 1,
                                                }),
                                            )
                                        }
                                    />
                                </InlineStack>
                            </BlockStack>
                        )}
                    </MainLayout.Content>
                </MainLayout.ContentWrapper>
            </MainLayout>
        </SettingsRoute>
    );
    /* </fs_premium_only> */

    return (
        <MainLayout>
            <MainLayout.ContentWrapper>
                <Topbar leftContents={[title]} />

                <MainLayout.Content>
                    <InlineStack gap={10} align="between">
                        <InlineStack gap={5}>
                            <Text color="gray-700" weight="semibold">
                                {__("All User Access", "ninja-drive")}
                            </Text>

                            <Text color="gray-600" size="sm">
                                (0 {__("items", "ninja-drive")})
                            </Text>
                        </InlineStack>

                        <Button
                            variant="outlined"
                            size="small"
                            startIcon="info"
                            href=""
                            target="_blank"
                        >
                            {__("Documentation", "ninja-drive")}
                        </Button>
                    </InlineStack>

                    <AccessTopbar
                        data={[]}
                        selectedAccesses={selectedAccesses}
                        setSelectedAccesses={setSelectedAccesses}
                        onAdd={() => {}}
                    />

                    <AccessList
                        data={[]}
                        selectedAccesses={selectedAccesses}
                        setSelectedAccesses={setSelectedAccesses}
                        onAdd={() => {}}
                        loading={false}
                    />
                </MainLayout.Content>
            </MainLayout.ContentWrapper>
        </MainLayout>
    );
};

export default UserAccess;
