import { useAppDispatch, useAppSelector } from "~/store/hooks";
import { useCustomAlert } from "~/components/molecules/Alert";
import InlineStack from "~/components/molecules/InlineStack";
import { useNavigate, useParams } from "react-router-dom";
import Stepper from "~/components/atoms/Stepper";
import Divider from "~/components/atoms/Divider";
import Button from "~/components/atoms/Button";
import Input from "~/components/atoms/Input";
import { __ } from "@wordpress/i18n";
import {
    selectUserAccess,
    updateUserAccess,
} from "~/store/features/userAccessSlice";

const AccessTopbar = ({
    onSave,
    loading = false,
}: {
    onSave: (key: "stay" | "close") => void;
    loading: boolean;
}) => {
    const { edit_data, is_edited } = useAppSelector(selectUserAccess);

    const { access_id, accessMenu } = useParams();

    const dispatch = useAppDispatch();

    const { showAlert } = useCustomAlert();

    const navigate = useNavigate();

    const handleStepClick = (menuId: string) => {
        navigate(`/user-access/${access_id}/${menuId}`);
    };

    const handleBack = () => {
        if (is_edited) {
            showAlert({
                title: __("Unsaved Changes", "ninja-drive"),
                text: __(
                    "You have unsaved changes. Are you sure you want to go back?",
                    "ninja-drive",
                ),
                type: "warning",
                showCancelButton: true,
                confirmButtonText: __("Back", "ninja-drive"),
                onConfirm: () => {
                    navigate("/user-access");
                },
            });
            return;
        }

        navigate("/user-access");
    };

    const handleDismiss = () => {
        if (is_edited) {
            showAlert({
                title: __("Unsaved Changes", "ninja-drive"),
                text: __(
                    "You have unsaved changes. Are you sure you want to discard them?",
                    "ninja-drive",
                ),
                type: "warning",
                showCancelButton: true,
                confirmButtonText: __("Discard", "ninja-drive"),
                onConfirm: () => {
                    navigate(`/user-access/${access_id}/${accessMenu}`);
                },
            });
            return;
        }
        navigate(`/user-access/${access_id}/${accessMenu}`);
    };

    const handlePrev = () => {
        const currentIndex = MENUS?.findIndex(
            (menu) => menu.key === accessMenu,
        );

        if (currentIndex > 0) {
            const prevMenuKey = MENUS[currentIndex - 1].key;
            navigate(`/user-access/${access_id}/${prevMenuKey}`);
        }
    };

    const handleNext = () => {
        const currentIndex = MENUS?.findIndex(
            (menu) => menu.key === accessMenu,
        );

        if (currentIndex < MENUS.length - 1) {
            const nextMenuKey = MENUS[currentIndex + 1].key;
            navigate(`/user-access/${access_id}/${nextMenuKey}`);
        }
    };

    const isFirst = accessMenu === MENUS?.[0]?.key;

    const isLast = accessMenu === MENUS?.[MENUS.length - 1]?.key;

    const discard = (
        <Button
            variant="warning"
            startIcon="history"
            onClick={handleDismiss}
            disabled={!is_edited}
        >
            {__("Discard", "ninja-drive")}
        </Button>
    );

    const save = (
        <Button
            variant="primary"
            startIcon="check"
            onClick={() => onSave("stay")}
            loading={loading}
            disabled={!is_edited}
        >
            {__("Save Changes", "ninja-drive")}
        </Button>
    );

    return (
        <div
            style={{
                position: "sticky",
                top: 0,
                zIndex: 99999,
            }}
            className="bg-white"
        >
            <InlineStack>
                <Button
                    startIcon="chevron_backward"
                    iconSize="2xl"
                    style={{ padding: "20px" }}
                    onClick={handleBack}
                >
                    {__("Back To List", "ninja-drive")}
                </Button>

                <Divider variant="vertical" width="1px" height="80px" />

                <InlineStack padding={20} align="between" className="flex-1">
                    <Input
                        placeholder={__("User Access Title", "ninja-drive")}
                        fullWidth={false}
                        customWidth="250px"
                        background="gray-50"
                        color="gray-200"
                        style={{
                            paddingLeft: "40px",
                        }}
                        value={edit_data?.title || ""}
                        onChange={(value) =>
                            dispatch(updateUserAccess({ title: value }))
                        }
                    />

                    <InlineStack gap={10}>
                        {discard}

                        {save}
                    </InlineStack>
                </InlineStack>
            </InlineStack>

            <Divider width="100%" height="1px" />

            <InlineStack
                gap={20}
                align="between"
                style={{
                    padding: 20,
                }}
            >
                <div
                    style={{
                        opacity: isFirst ? 0 : 1,
                        transition: "opacity 0.3s",
                    }}
                >
                    <Button
                        variant="outlined"
                        startIcon="arrow_left_alt"
                        style={{
                            backgroundColor: "var(--pnpnd-gray-50)",
                        }}
                        onClick={handlePrev}
                        disabled={isFirst}
                    >
                        {__("Back", "ninja-drive")}
                    </Button>
                </div>

                <Stepper
                    steps={MENUS}
                    active={accessMenu || MENUS?.[0]?.key}
                    onStepperClick={(key) => handleStepClick(key)}
                />

                <div>
                    {isLast ? (
                        <Button
                            variant="primary"
                            startIcon="check"
                            onClick={() => onSave("close")}
                            loading={loading}
                            disabled={!is_edited}
                        >
                            {__("Finish", "ninja-drive")}
                        </Button>
                    ) : (
                        <Button
                            variant="primary"
                            endIcon="arrow_right_alt"
                            onClick={handleNext}
                            disabled={
                                isLast || edit_data?.folders?.length === 0
                            }
                        >
                            {__("Next", "ninja-drive")}
                        </Button>
                    )}
                </div>
            </InlineStack>
        </div>
    );
};

export default AccessTopbar;

const MENUS: { key: "source" | "permissions"; title: string }[] = [
    {
        key: "source",
        title: __("Source", "ninja-drive"),
    },
    {
        key: "permissions",
        title: __("Permissions", "ninja-drive"),
    },
];
