import { useSyncSettingsMutation } from "~/store/api/settingsApi";
import PageContainer from "~/components/molecules/PageContainer";
import UpgradeBanner from "~/components/organisms/UpgradeBanner";
import SettingsField from "~/components/molecules/SettingsField";
import AssignFolder from "~/components/molecules/AssignFolder";
import { selectSettings } from "~/store/features/settingSlice";
import { useCustomAlert } from "~/components/molecules/Alert";
import Description from "~/components/molecules/Description";
import InlineStack from "~/components/molecules/InlineStack";
import BlockStack from "~/components/molecules/BlockStack";
import SelectBox from "~/components/molecules/SelectBox";
import Disabled from "~/components/molecules/Disabled";
import useSaveSettings from "~/hooks/useSaveSettings";
import Switcher from "~/components/atoms/Switcher";
import { useAppSelector } from "~/store/hooks";
import Button from "~/components/atoms/Button";
import { toBoolean } from "~/utils/functions";
import { useState } from "@wordpress/element";
import Input from "~/components/atoms/Input";
import Icon from "~/components/atoms/Icon";
import Text from "~/components/atoms/Text";
import { __ } from "@wordpress/i18n";
import DOCS from "~/utils/docs";
import clsx from "clsx";

const Synchronization = () => {
    const { data } = useAppSelector(selectSettings);
    const { saveSynchronization } = useSaveSettings();
    const [syncSettings] = useSyncSettingsMutation();
    const [syncLoading, setSyncLoading] = useState(false);

    const { showAlert } = useCustomAlert();

    const { enable_sync, folders, timer, custom_timer } =
        data?.synchronization || {};

    const [inputTimer, setInputTimer] = useState<number>(custom_timer || 60);
    const [error, setError] = useState<string>();

    const handleTimer = (value: number) => {
        setInputTimer(value);
        setError("");

        if (value < 30) {
            setError(
                __("Custom time must be at least 30 seconds.", "ninja-drive"),
            );
            return;
        }

        if (value > 2592000) {
            setError(
                __("Custom time cannot exceed 2592000 seconds.", "ninja-drive"),
            );
            return;
        }

        saveSynchronization("custom_timer", value);
    };

    const handleSync = async () => {
        showAlert({
            type: "info",
            title: __("Synchronization", "ninja-drive"),
            text: __(
                "Are you sure you want to synchronize now?",
                "ninja-drive",
            ),
            showCancelButton: true,
            confirmButtonText: __("Synchronize", "ninja-drive"),
            onConfirm: async () => {
                setSyncLoading(true);
                try {
                    const response = await syncSettings().unwrap();

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.data?.message ||
                            __(
                                "Synchronization completed successfully",
                                "ninja-drive",
                            ),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });

                    setSyncLoading(false);
                } catch (error: any) {
                    setSyncLoading(false);

                    showAlert({
                        toast: true,
                        type: "error",
                        text:
                            error?.data?.message ||
                            __("Failed to synchronize", "ninja-drive"),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };

    if (!toBoolean(pnpnd.is_pro)) {
        return (
            <UpgradeBanner
                title={__(
                    "Synchronization is a Pro feature. Upgrade to seamlessly synchronize your Google Drive with the WordPress media library, enabling easy access and management of your cloud files directly from your media library.",
                    "ninja-drive",
                )}
            />
        );
    }

    return (
        <PageContainer compact style={{ margin: "0 auto" }}>
            {/* <fs_premium_only> */}
            <SettingsField
                description={__(
                    "Enable or disable the local cache file auto synchronization with the cloud files.",
                    "ninja-drive",
                )}
                docLink={DOCS.SETTINGS.synchronization.authSync}
                action={
                    <Switcher
                        id="enableAutoSync"
                        isPro={true}
                        title={__("Enable Auto Synchronization", "ninja-drive")}
                        titleSize="sm"
                        checked={enable_sync}
                        onChange={() => {
                            if (!toBoolean(pnpnd.is_pro)) return;

                            saveSynchronization("enable_sync", !enable_sync);
                        }}
                    />
                }
            >
                <Disabled
                    depend={!enable_sync}
                    dependOn="enableAutoSync"
                    gap={15}
                >
                    <AssignFolder
                        title={__("Assigned Folders", "ninja-drive")}
                        description={__(
                            "Select the Google Drive folders to synchronize with your WordPress media library. You can assign multiple folders, and they will be automatically synchronized based on the timer settings below.",
                            "ninja-drive",
                        )}
                        selected={folders || []}
                        onSelect={(folder) =>
                            saveSynchronization("folders", folder)
                        }
                        sync={
                            <Button
                                variant="secondary"
                                size="small"
                                color="primary"
                                style={{
                                    backgroundColor:
                                        "var(--pnpnd-primary-extralight)",
                                }}
                                onClick={handleSync}
                            >
                                <Icon
                                    name="refresh"
                                    color="primary"
                                    fontSize="lg"
                                    className={clsx(syncLoading && "loading")}
                                />
                                {__("Sync", "ninja-drive")}
                            </Button>
                        }
                    />

                    <BlockStack gap={10}>
                        <InlineStack gap={10}>
                            <Text color="gray-700" size="sm" weight="medium">
                                {__(
                                    "Select Timer For Auto Synchronization",
                                    "ninja-drive",
                                )}
                            </Text>

                            <SelectBox
                                background="gray-50"
                                color="gray-200"
                                size="small"
                                style={{
                                    width: "200px",
                                }}
                                options={SYNC_CUSTOM_TIMER}
                                value={[timer || "custom"]}
                                onChange={(value) =>
                                    saveSynchronization("timer", value[0])
                                }
                            />
                        </InlineStack>

                        <Description
                            text={__(
                                "Set how frequently the plugin should automatically synchronize assigned folders with Google Drive.",
                                "ninja-drive",
                            )}
                        />
                    </BlockStack>

                    <Disabled depend={timer !== "custom"}>
                        <BlockStack gap={10}>
                            <InlineStack gap={10}>
                                <Text
                                    color="gray-700"
                                    size="sm"
                                    weight="medium"
                                >
                                    {__("Select Custom timer", "ninja-drive")}
                                </Text>

                                <Input
                                    type="number"
                                    size="small"
                                    background="gray-50"
                                    color="gray-200"
                                    fullWidth={false}
                                    customWidth="200px"
                                    min={60}
                                    max={2592000}
                                    value={inputTimer}
                                    onChange={(value) =>
                                        handleTimer(Number(value))
                                    }
                                    error={!!error}
                                    errorText={error}
                                />
                            </InlineStack>

                            <Description
                                text={__(
                                    "Enter the custom synchronization interval (min: 60 seconds).",
                                    "ninja-drive",
                                )}
                            />
                        </BlockStack>
                    </Disabled>
                </Disabled>
            </SettingsField>
            {/* </fs_premium_only> */}
        </PageContainer>
    );
};

export default Synchronization;

const SYNC_CUSTOM_TIMER: { name: string; value: string }[] = [
    { name: __("5 Minutes", "ninja-drive"), value: "300" },
    { name: __("10 Minutes", "ninja-drive"), value: "600" },
    { name: __("15 Minutes", "ninja-drive"), value: "900" },
    { name: __("30 Minutes", "ninja-drive"), value: "1800" },
    { name: __("1 Hour", "ninja-drive"), value: "3600" },
    { name: __("5 Hours", "ninja-drive"), value: "18000" },
    { name: __("1 Day", "ninja-drive"), value: "86400" },
    { name: __("1 Week", "ninja-drive"), value: "604800" },
    { name: __("Custom", "ninja-drive"), value: "custom" },
];
