import SettingsField from "~/components/molecules/SettingsField";
import UpgradeBanner from "~/components/organisms/UpgradeBanner";
import { selectSettings } from "~/store/features/settingSlice";
import AssignFolder from "~/components/molecules/AssignFolder";
import { useCustomAlert } from "~/components/molecules/Alert";
import InlineStack from "~/components/molecules/InlineStack";
import Description from "~/components/molecules/Description";
import BlockStack from "~/components/molecules/BlockStack";
import useSaveSettings from "~/hooks/useSaveSettings";
import Switcher from "~/components/atoms/Switcher";
import Divider from "~/components/atoms/Divider";
import { Integrations } from "~/types/settings";
import { useAppSelector } from "~/store/hooks";
import Button from "~/components/atoms/Button";
import { toBoolean } from "~/utils/functions";
import { useState } from "@wordpress/element";
import Icon from "~/components/atoms/Icon";
import Text from "~/components/atoms/Text";
import { __ } from "@wordpress/i18n";
import clsx from "clsx";
import {
    useClearAttachmentsMutation,
    useMediaLibrarySyncMutation,
} from "~/store/api/mediaLibraryApi__premium_only";

const MediaLibrary = () => {
    const { data } = useAppSelector(selectSettings);
    const [mediaLibrarySync] = useMediaLibrarySyncMutation();
    const [clearAttachments] = useClearAttachmentsMutation();
    const [syncLoading, setSyncLoading] = useState(false);

    const { saveIntegrations } = useSaveSettings();

    const { showAlert } = useCustomAlert();

    const { folders, delete_cloud_file } =
        data?.integrations?.media_library || {};

    const handleMediaLibrarySync = async () => {
        setSyncLoading(true);

        try {
            const response = await mediaLibrarySync().unwrap();

            setSyncLoading(false);

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    __("Media library synced successfully", "ninja-drive"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        } catch (error: any) {
            setSyncLoading(false);

            showAlert({
                toast: true,
                type: "error",
                text:
                    error?.data?.message ||
                    __("Failed to sync media library", "ninja-drive"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const handleClearAttachments = async () => {
        showAlert({
            type: "error",
            title: __("Clear Attachments", "ninja-drive"),
            text: __(
                "Are you sure you want to clear all attachments from the media library?",
                "ninja-drive",
            ),
            showCancelButton: true,
            confirmButtonText: __("Clear", "ninja-drive"),
            onConfirm: async () => {
                try {
                    const response =
                        (await clearAttachments().unwrap()) as unknown as {
                            message?: string;
                        };

                    showAlert({
                        toast: true,
                        type: "success",
                        text:
                            response?.message ||
                            __(
                                "Attachments cleared successfully!",
                                "ninja-drive",
                            ),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                } catch (error: any) {
                    showAlert({
                        toast: true,
                        type: "error",
                        text:
                            error?.data?.message ||
                            __("Failed to clear attachments!", "ninja-drive"),
                        timer: 3000,
                        timerProgressBar: true,
                        showConfirmButton: false,
                    });
                }
            },
        });
    };

    if (!toBoolean(pnpnd.is_pro)) {
        return (
            <UpgradeBanner
                title={__(
                    "Media Library integration is a Pro feature. Upgrade to seamlessly integrate your Google Drive with the WordPress media library, enabling easy access and management of your cloud files directly from your media library.",
                    "ninja-drive",
                )}
            />
        );
    }

    return (
        <SettingsField
            compact
            style={{
                margin: "0 auto",
            }}
        >
            <AssignFolder
                title={__("Assigned Folders", "ninja-drive")}
                description={__(
                    "Select the Google Drive folders to integrate with your WordPress media library. You can assign multiple folders, and they will appear as separate sections within the media library for easy access and organization.",
                    "ninja-drive",
                )}
                selected={folders || []}
                onSelect={(folder) =>
                    saveIntegrations("media_library", {
                        ...data?.integrations?.media_library,
                        folders: folder,
                    } as Integrations["media_library"])
                }
                sync={
                    <Button
                        variant="secondary"
                        size="small"
                        color="primary"
                        style={{
                            backgroundColor: "var(--pnpnd-primary-extralight)",
                        }}
                        onClick={handleMediaLibrarySync}
                    >
                        <Icon
                            name="refresh"
                            color="primary"
                            fontSize="lg"
                            className={clsx(syncLoading && "loading")}
                        />
                        {__("Sync", "ninja-drive")}
                    </Button>
                }
            />

            <Divider width="100%" height="1px" />

            <BlockStack gap={10}>
                <Switcher
                    title={__(
                        "Delete Cloud Files on Attachment Delete",
                        "ninja-drive",
                    )}
                    titleSize="sm"
                    checked={delete_cloud_file}
                    onChange={() =>
                        saveIntegrations("media_library", {
                            ...data?.integrations?.media_library,
                            delete_cloud_file: !delete_cloud_file,
                        } as Integrations["media_library"])
                    }
                />

                <Description
                    text={__(
                        "When enabled, deleting an attachment will also delete the corresponding file from the cloud storage.",
                        "ninja-drive",
                    )}
                />
            </BlockStack>

            <Divider width="100%" height="1px" />

            <BlockStack gap={10}>
                <InlineStack gap={10}>
                    <Text color="gray-700" size="sm" weight="medium">
                        {__("Clear Attachments", "ninja-drive")}
                    </Text>

                    <Button
                        variant="error"
                        size="small"
                        startIcon="cached"
                        onClick={handleClearAttachments}
                    >
                        {__("Clear Attachments", "ninja-drive")}
                    </Button>
                </InlineStack>

                <Description
                    text={__(
                        "Remove all Google Drive attachments currently integrated into your media library.",
                        "ninja-drive",
                    )}
                />
            </BlockStack>
        </SettingsField>
    );
};

export default MediaLibrary;
