import UpgradeBanner from "~/components/organisms/UpgradeBanner";
import MainLayout from "~/components/templates/MainLayout";
import BlockStack from "~/components/molecules/BlockStack";
import Loading from "~/components/atoms/Loading";
import { __ } from "@wordpress/i18n";
/* <fs_premium_only> */
import { useAppDispatch, useAppSelector } from "~/store/hooks";
import { useCustomAlert } from "~/components/molecules/Alert";
import { useNavigate, useParams } from "react-router-dom";
import Permissions from "./pages/Permissions/Permissions";
import Source from "./pages/Source__premium_only/Source";
import AccessTopbar from "./AccessTopbar__premium_only";
import SettingsRoute from "~/Routes/SettingsRoute";
import { useEffect } from "@wordpress/element";
import {
    useCreateUserAccessMutation,
    useGetUserAccessQuery,
} from "~/store/api/userAccessApi__premium_only";
import {
    selectUserAccess,
    setIsEdited,
    userAccessInit,
} from "~/store/features/userAccessSlice";
/* </fs_premium_only> */

const UserAccess = () => {
    /* <fs_premium_only> */
    const { edit_data, default_data, roles, users, is_edited } =
        useAppSelector(selectUserAccess);
    const [createUserAccess, { isLoading: isSaving }] =
        useCreateUserAccessMutation();

    const { access_id, accessMenu } = useParams();

    const { data, isLoading } = useGetUserAccessQuery({
        id: access_id || "new",
        remaining: 1,
    });

    const dispatch = useAppDispatch();

    const { showAlert } = useCustomAlert();

    const navigate = useNavigate();

    useEffect(() => {
        if (data) {
            dispatch(
                userAccessInit({
                    edit_data: data?.data?.access || null,
                    default_data: data?.data?.access || null,
                    roles: data?.data?.remaining?.roles || [],
                    users: data?.data?.remaining?.users || [],
                }),
            );
        }
    }, [data]);

    useEffect(() => {
        dispatch(
            setIsEdited(
                JSON.stringify(default_data) !== JSON.stringify(edit_data),
            ),
        );
    }, [data, edit_data]);

    useEffect(() => {
        if (edit_data?.folders?.length === 0 && accessMenu !== "source") {
            console.log("first");
            showAlert({
                toast: true,
                type: "error",
                text: __(
                    "Please select at least one folder to proceed.",
                    "ninja-drive",
                ),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });

            navigate(`/user-access/${access_id}/source/my-drive`);
        }
    }, [edit_data?.folders, accessMenu]);

    useEffect(() => {
        const handleBeforeUnload = (e: BeforeUnloadEvent) => {
            e.preventDefault();
            e.returnValue = "";
        };
        if (is_edited) {
            window.addEventListener("beforeunload", handleBeforeUnload);
        }

        return () => {
            window.removeEventListener("beforeunload", handleBeforeUnload);
        };
    }, [is_edited]);

    const handleSave = async (key: "stay" | "close") => {
        if (!edit_data) return;

        if (edit_data?.folders?.length === 0) {
            showAlert({
                toast: true,
                type: "error",
                text: __(
                    "Please select at least one folder to proceed.",
                    "ninja-drive",
                ),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
            return;
        }

        try {
            const response = await createUserAccess({
                data: edit_data,
            }).unwrap();

            dispatch(
                userAccessInit({
                    edit_data: response?.data,
                    default_data: response?.data,
                    roles: roles || [],
                    users: users || [],
                }),
            );

            showAlert({
                toast: true,
                type: "success",
                text:
                    response?.message ||
                    __("User access created successfully", "ninja-drive"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });

            if (key === "stay") {
                if (accessMenu === "source") {
                    navigate(
                        `/user-access/${response?.data?.id}/${accessMenu}/my-drive`,
                    );
                } else {
                    navigate(
                        `/user-access/${response?.data?.id}/${accessMenu}`,
                    );
                }
            } else {
                navigate("/user-access");
            }
        } catch (error: any) {
            showAlert({
                toast: true,
                type: "error",
                text:
                    error?.data?.message ||
                    __("An error occurred", "ninja-drive"),
                timer: 3000,
                timerProgressBar: true,
                showConfirmButton: false,
            });
        }
    };

    const renderPage = () => {
        switch (accessMenu) {
            case "source":
                return <Source />;
            case "permissions":
                return <Permissions />;
            default:
                return <Source />;
        }
    };

    if (isLoading) {
        return (
            <BlockStack align="center" inlineAlign="center" className="h-full">
                <Loading />
            </BlockStack>
        );
    }

    return (
        <SettingsRoute>
            <MainLayout>
                <MainLayout.ContentWrapper>
                    <AccessTopbar onSave={handleSave} loading={isSaving} />

                    <MainLayout.Content
                        style={{
                            paddingBottom: "100px",
                        }}
                    >
                        {renderPage()}
                    </MainLayout.Content>
                </MainLayout.ContentWrapper>
            </MainLayout>
        </SettingsRoute>
    );
    /* </fs_premium_only> */

    return (
        <MainLayout>
            <MainLayout.ContentWrapper>
                <MainLayout.Content>
                    <UpgradeBanner />
                </MainLayout.Content>
            </MainLayout.ContentWrapper>
        </MainLayout>
    );
};

export default UserAccess;
