import { useUserStatusMutation } from "~/store/api/userAccessApi__premium_only";
import MainLayout from "~/components/templates/MainLayout/MainLayout";
import FilesViews from "~/components/organisms/FilesViews/FilesViews";
import FileInfo from "~/components/organisms/FilesViews/FileInfo";
import SettingsField from "~/components/molecules/SettingsField";
import PageContainer from "~/components/molecules/PageContainer";
import Uploader from "~/components/organisms/Uploader/Uploader";
import { useAppDispatch, useAppSelector } from "~/store/hooks";
import Description from "~/components/molecules/Description";
import InlineStack from "~/components/molecules/InlineStack";
import BlockStack from "~/components/molecules/BlockStack";
import { useNavigate, useParams } from "react-router-dom";
import SelectBox from "~/components/molecules/SelectBox";
import { useEffect, useState } from "@wordpress/element";
import { useFileActions } from "~/hooks/useFileActions";
import { checkSelectionFiles } from "~/utils/helpers";
import { MENU_KEYS, MenuKey } from "~/types/Types";
import SelectedFileList from "./SelectedFileList";
import { useGallery } from "~/hooks/useGallery";
import Card from "~/components/molecules/Card";
import Radio from "~/components/atoms/Radio";
import { useFiles } from "~/hooks/useFiles";
import Text from "~/components/atoms/Text";
import { File } from "~/types/file.types";
import { isFolder } from "~/utils/file";
import { __ } from "@wordpress/i18n";
import { TLayout } from "~/types/ui";
import FileSidebar from "./Sidebar";
import FileTopbar from "./Topbar";
import DOCS from "~/utils/docs";
import {
    selectUserAccess,
    updateUserAccess,
} from "~/store/features/userAccessSlice";

const Source = () => {
    const [showUploader, setShowUploader] = useState(false);
    const [layout, setLayout] = useState<TLayout>("grid");
    const [selectedFiles, setSelectedFiles] = useState<File[]>([]);

    const { edit_data, roles, users } = useAppSelector(selectUserAccess);

    const [userStatusMutation] = useUserStatusMutation();

    const [statusMessage, setStatusMessage] = useState<string>("");

    const navigate = useNavigate();

    const dispatch = useAppDispatch();

    const { menuKey, access_id } = useParams<{
        menuKey?: MenuKey;
        access_id?: string;
    }>();

    const {
        files,
        breadcrumbs,
        openFolder,
        loading,
        loadMoreRef,
        has_more,
        loadingMore,
        refresh,
        queryArgs,
        setQueryArgs,
    } = useFiles("my-drive", false, ["all"]);

    const { active_folder, order, order_by } = queryArgs;

    const rolesOptions =
        roles?.map((role) => ({
            name: role.charAt(0).toUpperCase() + role.slice(1),
            value: role,
        })) || [];

    const usersOptions =
        users?.map((user) => ({
            name: user,
            value: user,
        })) || [];

    const { viewFile } = useGallery(files);

    const {
        activeFile,
        createFolder,
        deleteFile,
        rename,
        download,
        viewDetails,
        openGoogleDrive,
        move,
        copy,
        share,
    } = useFileActions();

    useEffect(() => {
        if (active_folder && MENU_KEYS?.includes(active_folder as MenuKey)) {
            navigate(`/user-access/${access_id}/source/${active_folder}`);
        }
    }, [active_folder]);

    useEffect(() => {
        if (
            menuKey &&
            breadcrumbs?.length &&
            !breadcrumbs?.some((b) => b?.file_key === menuKey)
        ) {
            openFolder(menuKey);
        }
    }, [menuKey]);

    useEffect(() => {
        if (edit_data?.folders?.length && files?.length) {
            const matchedFiles = files.filter((file) =>
                edit_data.folders.includes(file.file_key),
            );
            if (matchedFiles.length > 0) {
                setSelectedFiles((prev) => {
                    const existingKeys = new Set(prev.map((f) => f.file_key));
                    const newMatches = matchedFiles.filter(
                        (f) => !existingKeys.has(f.file_key),
                    );
                    return newMatches.length > 0
                        ? [...prev, ...newMatches]
                        : prev;
                });
            }
        }
    }, [edit_data?.folders, files]);

    const handleSelectFile = (newSelectedFiles: File | File[]) => {
        if (active_folder === "home") return;

        const _newSelectedFiles = checkSelectionFiles(
            newSelectedFiles,
            selectedFiles,
        );
        setSelectedFiles(_newSelectedFiles);
        dispatch(
            updateUserAccess({
                folders: _newSelectedFiles.map((f) => f.file_key),
            }),
        );
    };

    const handleDoubleClick = (file: File) => {
        if (isFolder(file?.extension || "")) {
            openFolder(file?.file_key);
        } else {
            viewFile(file?.file_key);
        }
    };

    const handleContextMenuClick = (actionId: string, file: File) => {
        switch (actionId) {
            case "preview":
                viewFile(file.file_key);
                break;
            case "open":
                openGoogleDrive(file);
                break;
            case "view-details":
                if (viewDetails) viewDetails(file);
                break;
            case "share":
                share(file);
                break;
            case "download":
                download(file);
                break;
            case "copy":
                copy({
                    file,
                    widget_id: "",
                    active_folder_key: active_folder,
                    breadcrumbs,
                });
                break;
            case "move":
                move({
                    file,
                    widget_id: "",
                    active_folder_key: active_folder,
                    breadcrumbs,
                });
                break;
            case "rename":
                rename(file, active_folder);
                break;
            case "delete":
                const file_keys =
                    selectedFiles.length > 0
                        ? selectedFiles.map((file) => file?.file_key)
                        : [file?.file_key];
                deleteFile(file_keys, active_folder);
                break;
            default:
                break;
        }
    };

    const handleUserStatus = async (username: string) => {
        try {
            const response = await userStatusMutation({
                username,
            }).unwrap();

            if (response?.data?.status === "active") {
                setStatusMessage(
                    response?.data?.message ||
                        __("User already used.", "ninja-drive"),
                );
            }

            return response?.data?.status === "not-found";
        } catch (error) {
            return false;
        }
    };

    const uploader = (
        <Uploader
            background="white"
            borderStyle="dashed"
            shadow
            data={{
                minFileSize: 0,
                maxFileSize: pnpnd.is_pro ? 5 : 0,
                activeFolder: active_folder,
                onFileUpload: () => {},
                setIsUploading: setShowUploader,
                uploadImmediately: true,
                enableFolderUpload: true,
            }}
            onClose={() => setShowUploader(false)}
        />
    );

    return (
        <BlockStack gap={20}>
            <PageContainer
                title={__("Who Can See", "ninja-drive")}
                docLink={DOCS?.USER_ACCESS?.link}
            >
                <SettingsField>
                    <InlineStack gap={10}>
                        <Text color="gray-700" size="sm" weight="medium">
                            {__("User Access", "ninja-drive")}
                        </Text>

                        {BASE_OPTIONS?.map(({ key, title }, index) => (
                            <Radio
                                key={key ?? index}
                                title={title}
                                checked={key === edit_data?.type}
                                onChange={() =>
                                    dispatch(updateUserAccess({ type: key }))
                                }
                            />
                        ))}
                    </InlineStack>

                    <BlockStack gap={10}>
                        <InlineStack gap={10}>
                            <Text color="gray-700" size="sm" weight="medium">
                                {edit_data?.type === "role"
                                    ? __("Select Role", "ninja-drive")
                                    : __("Select User", "ninja-drive")}
                            </Text>

                            <SelectBox
                                background="gray-50"
                                color="gray-200"
                                style={{
                                    minWidth: "160px",
                                }}
                                options={
                                    edit_data?.type === "role"
                                        ? rolesOptions
                                        : usersOptions
                                }
                                value={[edit_data?.value || ""]}
                                onChange={async (value) => {
                                    if (edit_data?.type === "user") {
                                        setStatusMessage("");

                                        await handleUserStatus(value[0]);

                                        dispatch(
                                            updateUserAccess({
                                                value: value[0],
                                            }),
                                        );

                                        return;
                                    }

                                    dispatch(
                                        updateUserAccess({ value: value[0] }),
                                    );
                                }}
                            />

                            {!!statusMessage && (
                                <Text color="error" size="sm">
                                    {statusMessage}
                                </Text>
                            )}
                        </InlineStack>

                        <Description
                            text={__(
                                "Note: Roles and users can solely access folders assigned in the Access Backend File Browser settings above.",
                                "ninja-drive",
                            )}
                        />
                    </BlockStack>
                </SettingsField>
            </PageContainer>

            <PageContainer
                title={__("Select Folders and Files", "ninja-drive")}
                docLink={DOCS?.USER_ACCESS?.link}
            >
                <Card background="white" border="gray-200">
                    <InlineStack blockAlign="start" gap={20} wrap={false}>
                        <Card
                            style={{
                                position: "sticky",
                                top: 0,
                                height: "80vh",
                                overflow: "hidden",
                            }}
                            background="white"
                            padding={0}
                        >
                            <MainLayout
                                style={{
                                    borderRadius: "12px",
                                }}
                                className="pnpnd-widget-builder-layout"
                            >
                                <FileSidebar
                                    border={false}
                                    className="pnpnd-widget-file-sidebar"
                                    activeFolder={active_folder}
                                    sorting={{ order, order_by }}
                                    loading={loading}
                                    openFolder={openFolder}
                                />

                                <MainLayout.ContentWrapper>
                                    <MainLayout.Content
                                        style={{
                                            display: "flex",
                                            alignItems: "flex-start",
                                            gap: "20px",
                                            borderRadius: "12px",
                                            padding: "0px 20px 20px 20px",
                                        }}
                                        className="bg-white"
                                    >
                                        <FilesViews
                                            onFileClick={handleSelectFile}
                                            onFileDoubleClick={
                                                handleDoubleClick
                                            }
                                            isFileSelecting={true}
                                            setIsFileSelecting={() => {}}
                                            layout={layout}
                                            setLayout={setLayout}
                                            files={files}
                                            activeFolder={active_folder}
                                            breadcrumbs={breadcrumbs}
                                            openFolder={openFolder}
                                            activeFile={activeFile}
                                            setActiveFile={viewDetails}
                                            selected_files={selectedFiles}
                                            setSelectedFiles={handleSelectFile}
                                            filesStatus={{
                                                loading,
                                                loadingMore,
                                                has_more,
                                            }}
                                            showUploader={showUploader}
                                            setShowUploader={setShowUploader}
                                            sorting={{ order, order_by }}
                                            setSorting={(value) =>
                                                setQueryArgs({
                                                    ...queryArgs,
                                                    ...value,
                                                })
                                            }
                                        >
                                            <FileTopbar
                                                style={{
                                                    position: "sticky",
                                                    top: 0,
                                                }}
                                                activeFolder={active_folder}
                                                queryArgs={queryArgs}
                                                expandSearch={setQueryArgs}
                                                createFolder={createFolder}
                                                refresh={refresh}
                                                loading={loading}
                                            >
                                                <FilesViews.Breadcrumbs />
                                            </FileTopbar>

                                            <FilesViews.Header
                                                background="primary-extralight"
                                                marginTop={5}
                                            />

                                            <FilesViews.Files
                                                style={{
                                                    marginTop: "20px",
                                                    paddingBottom: "100px",
                                                }}
                                            />

                                            <FilesViews.FileContextMenu
                                                onMenuClick={
                                                    handleContextMenuClick
                                                }
                                            />

                                            {has_more && (
                                                <div
                                                    ref={loadMoreRef}
                                                    style={{
                                                        height: "20px",
                                                        marginTop: "-20px",
                                                    }}
                                                />
                                            )}
                                        </FilesViews>

                                        {activeFile && (
                                            <FileInfo
                                                activeFile={activeFile}
                                                onClose={() =>
                                                    viewDetails(undefined)
                                                }
                                            />
                                        )}

                                        {showUploader && uploader}
                                    </MainLayout.Content>
                                </MainLayout.ContentWrapper>
                            </MainLayout>
                        </Card>

                        <SelectedFileList
                            selected_files={selectedFiles}
                            setSelectedFiles={(newSelectedFiles) => {
                                setSelectedFiles(newSelectedFiles);
                                dispatch(
                                    updateUserAccess({
                                        folders: newSelectedFiles.map(
                                            (f) => f.file_key,
                                        ),
                                    }),
                                );
                            }}
                        />
                    </InlineStack>
                </Card>
            </PageContainer>
        </BlockStack>
    );
};

export default Source;

const BASE_OPTIONS: { key: "role" | "user"; title: string }[] = [
    {
        key: "role",
        title: __("Role Base", "ninja-drive"),
    },
    {
        key: "user",
        title: __("User Base", "ninja-drive"),
    },
];
