import { UserAccess } from "~/types/userAccess";
import { ServerResponse } from "~/types/Types";
import { baseApi } from "./baseApi";

export const userAccessApi = baseApi.injectEndpoints({
    endpoints: (builder) => ({
        getUserAccessList: builder.query<
            ServerResponse<{
                user_access: {
                    list: UserAccess[];
                    has_more: boolean;
                    page: number;
                    per_page: number;
                    total: number;
                    total_pages: number;
                };
                remaining: {
                    roles: string[];
                    users: string[];
                };
            }>,
            {
                base: "all" | "role" | "user";
                search?: string;
                order_by?: "id" | "title" | "created_at" | "updated_at";
                status?: "all" | "active" | "inactive";
                order?: "asc" | "desc";
                page?: number;
                per_page?: number;
            }
        >({
            query: ({
                base,
                search,
                order_by,
                status,
                order,
                page,
                per_page,
            }) => {
                const params: Record<string, string | number> = {};

                if (base && base !== "all") params.type = base;
                if (search) params.search = search;
                if (order_by) params.order_by = order_by;
                if (status && status !== "all") params.status = status;
                if (order) params.order = order;
                if (page) params.page = page;
                if (per_page) params.per_page = per_page;

                return {
                    url: "user/access",
                    method: "GET",
                    params,
                };
            },

            providesTags: () => [{ type: "UserAccess" }],
        }),

        getUserAccess: builder.query<
            ServerResponse<{
                access: UserAccess;
                remaining: {
                    roles: string[];
                    users: string[];
                };
            }>,
            { id: string; remaining?: number }
        >({
            query: ({ id, remaining }) => ({
                url: `user/access/${id}`,
                method: "GET",
                params: { remaining },
            }),
        }),

        createUserAccess: builder.mutation<
            ServerResponse<UserAccess>,
            {
                data: UserAccess;
            }
        >({
            query: ({ data }) => ({
                url: "user/access",
                method: "POST",
                body: data,
            }),

            invalidatesTags: [{ type: "UserAccess" }],
        }),

        updateUserAccess: builder.mutation<
            ServerResponse<UserAccess>,
            {
                id: number;
                data: UserAccess;
            }
        >({
            query: ({ id, data }) => ({
                url: `user/access/${id}`,
                method: "PUT",
                body: data,
            }),

            onQueryStarted: async (
                { id, data },
                { dispatch, queryFulfilled, getState },
            ) => {
                const queries = (getState() as any)?.baseApi?.queries ?? {};
                const patches = Object.values(queries)
                    .filter(
                        (e: any) =>
                            e?.endpointName === "getUserAccessList" &&
                            e?.status === "fulfilled",
                    )
                    .map((e: any) =>
                        dispatch(
                            userAccessApi.util.updateQueryData(
                                "getUserAccessList",
                                e.originalArgs,
                                (draft) => {
                                    if (!draft?.data) return;
                                    const index =
                                        draft.data.user_access.list.findIndex(
                                            (access) => access.id === id,
                                        );
                                    if (index !== -1) {
                                        draft.data.user_access.list[index] = {
                                            ...draft.data.user_access.list[
                                                index
                                            ],
                                            ...data,
                                        };
                                    }
                                },
                            ),
                        ),
                    );

                try {
                    await queryFulfilled;
                } catch {
                    patches.forEach((p) => p.undo());
                }
            },
        }),

        deleteUserAccess: builder.mutation<
            ServerResponse<null>,
            { ids: number[] }
        >({
            query: ({ ids }) => ({
                url: "user/access",
                method: "DELETE",
                body: { ids },
            }),

            onQueryStarted: async (
                { ids },
                { dispatch, queryFulfilled, getState },
            ) => {
                const queries = (getState() as any)?.baseApi?.queries ?? {};
                const patches = Object.values(queries)
                    .filter(
                        (e: any) =>
                            e?.endpointName === "getUserAccessList" &&
                            e?.status === "fulfilled",
                    )
                    .map((e: any) =>
                        dispatch(
                            userAccessApi.util.updateQueryData(
                                "getUserAccessList",
                                e.originalArgs,
                                (draft) => {
                                    if (!draft?.data) return;
                                    draft.data.user_access.list =
                                        draft.data.user_access.list.filter(
                                            (access) =>
                                                !ids.includes(access.id),
                                        );
                                },
                            ),
                        ),
                    );

                try {
                    await queryFulfilled;
                } catch {
                    patches.forEach((p) => p.undo());
                }
            },
        }),

        userStatus: builder.mutation<
            ServerResponse<{
                status: "active" | "not-found";
                message: string;
            }>,
            {
                username: string;
            }
        >({
            query: ({ username }) => ({
                url: "user/access/status",
                method: "GET",
                params: { username },
            }),

            invalidatesTags: [{ type: "UserAccess" }],
        }),
    }),

    overrideExisting: false,
});

export const {
    useGetUserAccessListQuery,
    useGetUserAccessQuery,
    useCreateUserAccessMutation,
    useUpdateUserAccessMutation,
    useDeleteUserAccessMutation,
    useUserStatusMutation,
} = userAccessApi;
